def create_gear_icon():
    """Zeichnet dynamisch ein Zahnrad mit blauem T und weißem V."""
    from PIL import Image, ImageDraw

    # 64x64 transparentes Bild erzeugen
    img = Image.new("RGBA", (64, 64), (0, 0, 0, 0))
    draw = ImageDraw.Draw(img)

    cx, cy = 32, 32
    r_outer = 22
    r_inner = 14

    # 8 Zahnrad-Zähne zeichnen
    num_teeth = 8
    tooth_width = 8
    tooth_depth = 6
    for i in range(num_teeth):
        angle = i * (2 * math.pi / num_teeth)
        x1 = cx + (r_outer - tooth_depth) * math.cos(angle)
        y1 = cy + (r_outer - tooth_depth) * math.sin(angle)
        x2 = cx + (r_outer + tooth_depth) * math.cos(angle)
        y2 = cy + (r_outer + tooth_depth) * math.sin(angle)
        draw.line([x1, y1, x2, y2], fill=(128, 128, 128, 255), width=tooth_width)

    # Grauer Hauptring des Zahnrads
    draw.ellipse([cx - r_outer, cy - r_outer, cx + r_outer, cy + r_outer], fill=(128, 128, 128, 255))

    # Inneres Loch transparent stanzen
    draw.ellipse([cx - r_inner, cy - r_inner, cx + r_inner, cy + r_inner], fill=(0, 0, 0, 0))

    # Blaues 'T' in der Mitte zeichnen
    # Horizontaler Balken
    draw.line([22, 24, 42, 24], fill=(0, 102, 204, 255), width=4)
    # Vertikaler Stamm
    draw.line([32, 24, 32, 44], fill=(0, 102, 204, 255), width=4)

    # Weißes 'V' leicht überlagernd/versetzt zeichnen
    # Linker Schenkel
    draw.line([25, 34, 32, 46], fill=(255, 255, 255, 255), width=3)
    # Rechter Schenkel
    draw.line([32, 46, 39, 34], fill=(255, 255, 255, 255), width=3)

    return img


import atexit
import sys
import os

# Globaler Tracker für das aktive Tray-Icon, um saubere Bereinigung zu garantieren
_active_tray_icon = None


def cleanup_active_tray():
    """Wird beim Beenden von Python aufgerufen, um Tcl/Tk-Abstürze zu verhindern."""
    global _active_tray_icon
    if _active_tray_icon:
        try:
            _active_tray_icon.stop()
        except Exception:
            pass


# Registriere den Cleanup-Handler beim Interpreter-Shutdown
atexit.register(cleanup_active_tray)


def run_fallback_tray(tb_app):
    """Startet den systemkompatiblen Fallback-Tray-Runner ohne Thread-Abstürze."""
    global _active_tray_icon
    try:
        import pystray
    except ImportError:
        tb_app.sprint("pystray oder Pillow sind nicht installiert. Fallback-Tray startet nicht.")
        return

    import webbrowser

    def on_open_dashboard(icon, item):
        webbrowser.open("http://localhost:6587")

    def on_stop_all(icon, item):
        tb_app.sprint("Stopping background application from Tray...")
        icon.stop()
        # Explizite Bereinigung vor dem Exit
        cleanup_active_tray()
        os._exit(0)

    def get_menu():
        menu_items = [
            pystray.MenuItem("Open Dashboard", on_open_dashboard),
            pystray.Menu.SEPARATOR,
        ]
        if hasattr(tb_app, "daemon_app") and tb_app.daemon_app:
            menu_items.append(pystray.MenuItem("Runner: Active", lambda: None, enabled=False))
        menu_items.append(pystray.MenuItem("Quit Application", on_stop_all))
        return pystray.Menu(*menu_items)

    try:
        icon_img = create_gear_icon()
        icon = pystray.Icon(
            "tb_tray_runner",
            icon=icon_img,
            title="ToolBox Tray Runner",
            menu=pystray.Menu(lambda: get_menu())
        )

        _active_tray_icon = icon

        # Auf macOS muss der Tray zwingend im Hauptthread laufen
        if sys.platform == "darwin":
            import threading
            t = threading.Thread(target=tb_app.loop.run_forever, daemon=True)
            t.start()
            icon.run()
        else:
            # Unter Windows/Linux starten wir den Thread stabil.
            # Durch den atexit-Handler wird icon.stop() vor dem Hauptthread-Exit aufgerufen.
            import threading
            t = threading.Thread(target=icon.run, daemon=False)  # daemon=False verhindert abruptes Killen
            t.start()

    except Exception as e:
        tb_app.sprint(f"Fehler beim Starten des Fallback-Trays: {e}")
